import {INCREMENT, DELETE_ARTICLE, FILTER_ARTICLES} from '../types'

export const increment = () => ({
    type: INCREMENT
})

export const deleteArticle = (id) => ({
    type: DELETE_ARTICLE,
    payload: {id}
})

export const filterArticles = (id) => ({
    type: FILTER_ARTICLES,
    payload: {id}
})
